	mapSlice[0] = make(map[string]string, 10)
	mapSlice[0]["name"] = "小王子"
	mapSlice[0]["password"] = "123456"
	mapSlice[0]["address"] = "海淀区"
	for index, value := range mapSlice {
		fmt.Printf("index:%d value:%v\n", index, value)
	}
}
/*
index:0 value:map[]
index:1 value:map[]
index:2 value:map[]
#################### after init ################
index:0 value:map[address:海淀区 name:小王子 password:123456]
index:1 value:map[]
index:2 value:map[]
 */
```

## 03.map基本使用

### 3.1 判断某个键是否存在

```go
package main
import (
	"fmt"
)
func main() {
	userInfo := map[string]string{
		"username": "zhangsan",
		"password": "123456",
	}
	v, ok := userInfo["username"]
	if ok {
		fmt.Println(v)    // zhangsan
	}else {
		fmt.Println("map中没有此元素")
	}
}
```

### 3.2 delete()函数

- 使用 delete()内建函数从 map 中删除一组键值对，delete()函数的格式如下：delete(map 对象, key)
- 其中，
  - map 对象:表示要删除键值对的 map 对象
  - key:表示要删除的键值对的键

```go
package main
import (
	"fmt"
)
func main() {
	scoreMap := make(map[string]int)
	scoreMap["张三"] = 90
	scoreMap["小明"] = 100
	scoreMap["娜扎"] = 60
	delete(scoreMap, "小明")   //将小明:100 从 map 中删除
	for k,v := range scoreMap{
		fmt.Println(k, v)
	}
}
/*
娜扎 60
张三 90
 */
```

## 04.map遍历

### 4.1 遍历key和value

```go
package main
import (
	"fmt"
)
func main() {
	scoreMap := make(map[string]int)
	scoreMap["张三"] = 90
	scoreMap["小明"] = 100
	scoreMap["娜扎"] = 60
	for k, v := range scoreMap {
		fmt.Println(k, v)
	}
}
/*
张三 90
小明 100
娜扎 60
 */
```

### 4.2 只遍历Key

- 注意： 遍历 map 时的元素顺序与添加键值对的顺序无关

```go
package main
import (
   "fmt"
)
func main() {
   scoreMap := make(map[string]int)
   scoreMap["张三"] = 90
   scoreMap["小明"] = 100
   scoreMap["娜扎"] = 60
   for k := range scoreMap {
      fmt.Println(k)
   }
}
/*
张三
小明
娜扎
 */
```

### 4.3 顺序遍历map

```go
package main
import (
	"fmt"
	"sort"
)
func main() {
	// 第一：生成字典，scoreMap
	var scoreMap = make(map[string]int, 200)
	for i := 0; i < 10; i++ {
		key := fmt.Sprintf("stu%02d", i) //生成 stu 开头的字符串
		scoreMap[key] = i
	}

	// 第二：取出 map 中的所有 key 存入切片 keys
	var keys = make([]string, 0, 200)
	for key := range scoreMap {
		keys = append(keys, key)
	}

	// 第三：对切片进行排序
	sort.Strings(keys)

	// 第四：按照排序后的 key 遍历 map
	for _, key := range keys {
		fmt.Println(key, scoreMap[key])
	}
}
/*
stu00 0
stu01 1
stu02 2
stu03 3
stu04 4
stu05 5
stu06 6
stu07 7
stu08 8
stu09 9
 */
```

