	"encoding/json"
	"fmt"
)
type Student struct {   //Student 学生
	ID int
	Gender string
	Name string
}
type Class struct {   //Class 班级
	Title string
	Students []Student
}
func main() {
	c := &Class{
		Title:    "001",
		Students: make([]Student, 0, 200),
	}
	for i := 0; i < 10; i++ {
		stu := Student{
			Name:   fmt.Sprintf("stu%02d", i),
			Gender: "男",
			ID:     i,
		}
		c.Students = append(c.Students, stu)
	}
	//JSON 序列化：结构体-->JSON 格式的字符串
	data, err := json.Marshal(c)
	if err != nil {
		fmt.Println("json marshal failed")
		return
	}
	fmt.Printf("json:%s\n", data)
}
/*
{
    "Title":"001",
    "Students":[
        {
            "ID":0,
            "Gender":"男",
            "Name":"stu00"
        },
        {
            "ID":1,
            "Gender":"男",
            "Name":"stu01"
        },
        {
            "ID":2,
            "Gender":"男",
            "Name":"stu02"
        },
		....
    ]
}
 */
```

### 3.2 Json字符串转结构化

